export const nebraskaCountyMoverAssignments: CountyMoverAssignment[] = Object.entries(
  CURATED_NEBRASKA_COUNTIES
).map(([countySlug, moverIds]) => ({
  stateSlug: 'nebraska',
  countySlug,
  moverIds,
}));
